   457	void
   458	EmitIR::operator()(VarDecl* obj)
   459	{
   460	  auto ty = self(obj->type);
   461	
   462	  // Check if this is a global variable
   463	  if (mCurFunc == nullptr) {
   464	    // Global variable
   465	    llvm::Constant* initVal = nullptr;
   466	    if (obj->init) {
   467	      if (auto p = obj->init->dcst<IntegerLiteral>())
   468	        initVal = self(p);
   469	      else if (auto p = obj->init->dcst<InitListExpr>()) {
   470	        // Handle init list for arrays
   471	        std::vector<llvm::Constant*> elems;
   472	        for (auto&& e : p->list) {
   473	          if (auto il = e->dcst<IntegerLiteral>())
   474	            elems.push_back(self(il));
   475	          else
   476	            ABORT();
   477	        }
   478	        initVal = llvm::ConstantArray::get(llvm::dyn_cast<llvm::ArrayType>(ty), elems);
   479	      }
   480	    }
   481	    if (!initVal) {
   482	      // Default initializer
   483	      if (ty->isIntOrIntVectorTy())
   484	        initVal = llvm::ConstantInt::get(ty, 0);
   485	      else if (auto arrTy = llvm::dyn_cast<llvm::ArrayType>(ty))
   486	        initVal = llvm::ConstantAggregateZero::get(arrTy);
   487	      else
   488	        initVal = llvm::ConstantPointerNull::get(llvm::PointerType::get(mCtx, 0));
   489	    }
   490	    auto gv = new llvm::GlobalVariable(mMod, ty, false, llvm::GlobalVariable::ExternalLinkage, initVal, obj->name);
   491	    obj->any = gv;
   492	    return;
   493	  }
   494	
   495	  // Local variable - alloca
   496	  auto& irb = *mCurIrb;
   497	  auto alloca = irb.CreateAlloca(ty, nullptr, obj->name);
   498	  obj->any = alloca;
   499	
   500	  // Initialize
   501	  if (obj->init) {
   502	    if (auto p = obj->init->dcst<IntegerLiteral>()) {
   503	      irb.CreateStore(self(p), alloca);
   504	    } else if (auto p = obj->init->dcst<InitListExpr>()) {
   505	      // Handle init list for arrays
   506	      auto arrTy = llvm::dyn_cast<llvm::ArrayType>(ty);
   507	      if (!arrTy) ABORT();
   508	      for (unsigned i = 0; i < p->list.size(); ++i) {
   509	        auto elemPtr = irb.CreateInBoundsGEP(arrTy, alloca, {llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), 0), llvm::ConstantInt::get(llvm::Type::getInt32Ty(mCtx), i)});
   510	        if (auto il = p->list[i]->dcst<IntegerLiteral>())
   511	          irb.CreateStore(self(il), elemPtr);
   512	        else
   513	          ABORT();
   514	      }
   515	    } else {
   516	      auto val = self(obj->init);
   517	      irb.CreateStore(val, alloca);
   518	    }
   519	  } else {
   520	    // Default initialize to 0
   521	    if (ty->isIntOrIntVectorTy())
   522	      irb.CreateStore(llvm::ConstantInt::get(ty, 0), alloca);
   523	  }
   524	}
