   542	  unsigned idx = 0;
   543	  for (auto& arg : func->args()) {
   544	    if (idx < obj->params.size()) {
   545	      auto paramDecl = obj->params[idx];
   546	      auto alloca = mCurIrb->CreateAlloca(arg.getType(), nullptr, paramDecl->name);
   547	      mCurIrb->CreateStore(&arg, alloca);
   548	      paramDecl->any = alloca;
